// src/security/sanitizerPolicy.ts
import DOMPurify, { Config } from 'dompurify';

// Centralized, testable sanitization policy
export const RICH_TEXT_POLICY: Config = {
  ALLOWED_TAGS: [
    'b', 'strong', 'i', 'em', 'u', 'p', 'br', 'ul', 'ol', 'li',
    'span', 'a', 'code', 'pre', 'blockquote', 'h1', 'h2', 'h3'
  ],
  ALLOWED_ATTR: ['href', 'title', 'target', 'rel'],
  ALLOW_DATA_ATTR: false,
  FORBID_TAGS: ['script', 'style', 'iframe', 'object'],
  FORBID_ATTR: ['onerror', 'onclick', 'onload'],
  // Prevent javascript: URLs while still allowing http/https/mailto
  SAFE_FOR_TEMPLATES: true
};

export function sanitizeRichText(html: string): string {
  return DOMPurify.sanitize(html, RICH_TEXT_POLICY);
}

