  const safeHtml = sanitizedHtml || "<p>[content unavailable]</p>";

  // Logging for security monitoring (example, replace with real logger)
  const logSuspiciousContent = (original: string, sanitized: string) => {
    if (original !== sanitized) {
      // In production, send to your centralized logging / SIEM
      console.warn("[Security] Comment sanitized due to potential XSS", {
        commentId,
        originalLength: original.length,
        sanitizedLength: sanitized.length
      });
    }
  };

