        directives: {
          "default-src": ["'self'"],
          "script-src": ["'self'"],
          "img-src": ["'self'", "data:"],
          "object-src": ["'none'"],
          "base-uri": ["'self'"],
          "frame-ancestors": ["'none'"],
        },
