// server/routes/comments.ts
import express, { Request, Response } from "express";
import rateLimit from "express-rate-limit";
import { sanitizeRichHtml } from "../shared/sanitizer";

interface CommentInput {
  contentHtml: string;
}

const router = express.Router();

// Rate limiting to reduce abuse
const createCommentLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  standardHeaders: true,
  legacyHeaders: false,
});

router.post(
  "/comments",
  createCommentLimiter,
  async (req: Request, res: Response) => {
    try {
      const body = req.body as CommentInput;
      if (!body.contentHtml || typeof body.contentHtml !== "string") {
        return res.status(400).json({ error: "Invalid content" });
      }

      const sanitized = sanitizeRichHtml(body.contentHtml);
      if (!sanitized.trim()) {
        // Audit log for suspicious or empty content
        req.app.get("logger").warn("Comment fully stripped by sanitizer", {
          ip: req.ip,
          userId: req.user?.id ?? "anonymous",
        });
        return res.status(400).json({ error: "Content not allowed" });
      }

      // Persist only sanitized HTML to the database
      const savedComment = await req.app.get("db").comments.create({
        userId: req.user?.id,
        contentHtml: sanitized,
      });

      req.app.get("logger").info("Comment created", {
        commentId: savedComment.id,
        userId: req.user?.id ?? "anonymous",
      });

      return res.status(201).json(savedComment);
    } catch (err) {
      req.app.get("logger").error("Error creating comment", { error: err });
      return res.status(500).json({ error: "Internal server error" });
    }
  }
);

export default router;

