// nuxt-app/server/utils/htmlSanitizer.ts
import DOMPurify from 'isomorphic-dompurify';

// PRIMARY: shared sanitizer used on server (SSR) and client (hydration)
export function sanitizeUserHtml(dirty: string): string {
  return DOMPurify.sanitize(dirty, {
    ALLOWED_TAGS: [
      'b', 'strong', 'i', 'em', 'u',
      'p', 'br', 'ul', 'ol', 'li',
      'a', 'code', 'pre'
