// Simple in-memory rate limiting by IP for demo purposes
const requestCounts = new Map<string, { count: number; ts: number }>();

function isRateLimited(ip: string, limit = 60, windowMs = 60000): boolean {
  const now = Date.now();
  const entry = requestCounts.get(ip) || { count: 0, ts: now };
  if (now - entry.ts > windowMs) {
    entry.count = 0;
    entry.ts = now;
  }
  entry.count += 1;
  requestCounts.set(ip, entry);
  return entry.count > limit;
}

export default defineEventHandler(async (event) => {
  const ip = event.node.req.socket.remoteAddress || 'unknown';

  // DEFENSE: Basic rate limiting to reduce automated attack attempts
  if (isRateLimited(ip)) {
    event.node.res.statusCode = 429;
    return { error: 'Too many requests' };
  }

  const query = getQuery(event);
  const postId = Number(query.postId ?? '0');
  if (!Number.isInteger(postId) || postId <= 0) {
    event.node.res.statusCode = 400;
    return { error: 'Invalid postId' };
  }

  try {
    // Fetch from your database (placeholder data here)
