      }
    ];

    const safeComments = rawComments.map((c) => ({
      ...c,
      // SERVER-SIDE SANITIZATION before SSR
      content: sanitizeUserHtml(c.content)
    }));

    // AUDIT LOGGING: minimal info, no user secrets
    console.info('Comments served', { postId, count: safeComments.length, ip });

    event.node.res.setHeader('Content-Security-Policy', [
      "default-src 'self'",
      "script-src 'self' 'nonce-abc123'",
      "object-src 'none'",
      "base-uri 'self'",
