In production, you should centralize HTML handling, distinguish between trust levels (public users vs. admins vs. system), and implement defense in depth: strong sanitization, strict CSP, audit logging, and environment-specific controls.

**PRODUCTION PATTERN**:

```typescript
// src/security/htmlSanitizer.ts
import DOMPurify from "dompurify";

export type TrustLevel = "untrusted" | "trusted-admin" | "system";

export interface SanitizeOptions {
  trustLevel: TrustLevel;
}

// Centralized configuration: different allowlists per trust level
export const sanitizeHtml = (dirty: string, options: SanitizeOptions): string => {
  const baseConfig: DOMPurify.Config = {
    USE_PROFILES: { html: true },
    ALLOWED_TAGS: [
      "b",
      "strong",
      "i",
      "em",
      "u",
      "p",
      "br",
      "ul",
      "ol",
      "li",
      "a",
      "span",
      "code",
      "pre"
    ],
    ALLOWED_ATTR: ["href", "title", "target", "rel"]
  };

  let config: DOMPurify.Config = { ...baseConfig };

  if (options.trustLevel === "trusted-admin") {
    // Slightly richer formatting allowed for admin-authored content
    config = {
      ...config,
      ALLOWED_TAGS: [...config.ALLOWED_TAGS!, "h1", "h2", "h3", "blockquote", "img"],
      ALLOWED_ATTR: [...config.ALLOWED_ATTR!, "alt", "src"]
    };
  }

  if (options.trustLevel === "system") {
    // System content should ideally be static and pre-reviewed.
    // Still sanitize as a safety net.
    config = {
      ...config,
      FORBID_TAGS: ["script", "style"],
      FORBID_ATTR: ["onerror", "onclick", "onload"]
    };
  }

  return DOMPurify.sanitize(dirty, config);
};

// src/components/SafeHtml.tsx
import React from "react";
import { sanitizeHtml, TrustLevel } from "../security/htmlSanitizer";

export interface SafeHtmlProps {
  html: string;
  trustLevel?: TrustLevel;
  component?: keyof JSX.IntrinsicElements;
}

/**
 * A single, reusable component that owns all HTML injection.
 * All other components should use <SafeHtml> instead of dangerouslySetInnerHTML.
 */
export const SafeHtml: React.FC<SafeHtmlProps> = ({
  html,
  trustLevel = "untrusted",
  component: Tag = "div"
}) => {
  const safeHtml = React.useMemo(
    () => sanitizeHtml(html, { trustLevel }),
    [html, trustLevel]
  );

  return <Tag dangerouslySetInnerHTML={{ __html: safeHtml }} />;
};

