// src/api/client.ts (simplified fetch wrapper with logging and rate-limit hint)
import type { CommentProps } from "../components/Comment";

export interface ApiError extends Error {
  status?: number;
}

export const fetchJson = async <T>(
  input: RequestInfo,
  init?: RequestInit
): Promise<T> => {
  const response = await fetch(input, {
    credentials: "include",
    ...init
  });

  if (!response.ok) {
    const err: ApiError = new Error(`Request failed with status ${response.status}`);
    err.status = response.status;
    // Central place to hook into monitoring (e.g., Sentry, Datadog)
    console.error("API error", { url: input, status: response.status });
    throw err;
  }

  return (await response.json()) as T;
};

// src/pages/CommentsPage.tsx
import React from "react";
import { Comment } from "../components/Comment";
import { fetchJson } from "../api/client";

export const CommentsPage: React.FC = () => {
  const [comments, setComments] = React.useState<CommentProps[]>([]);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    let cancelled = false;

    const load = async () => {
      try {
        const data = await fetchJson<CommentProps[]>("/api/comments");
        if (!cancelled) {
          setComments(data);
        }
      } catch (e: unknown) {
        if (!cancelled) {
          console.error("Failed to load comments", e);
          setError("Unable to load comments right now. Please try again later.");
        }
      }
    };

    load();
    return () => {
      cancelled = true;
    };
  }, []);

  if (error) {
    return <div className="error" aria-live="polite">{error}</div>;
  }

  return (
    <main>
      <h1>User Comments</h1>
      {comments.map((c, i) => (
        <Comment key={i} {...c} />
      ))}
    </main>
  );
};

